int main() {
    int n, s;
    cin >> n >> s;
    vector<int> a(n);
    for (int i = 0; i < n; ++i) cin >> a[i];

    // Function to check if we can sort the array with the given constraints
    bool canSort(vector<int>& a, int s) {
        int cycleLengths[2 * n];
        int cycleCount = 0;
        for (int i = 0; i < n; ++i) {
            int index = a[i];
            while (index != i) {
                cycleLengths[cycleCount++] = index;
                index = a[index];
            }
        }

        // Check if the sum of cycle lengths exceeds s
        int totalCycleLength = 0;
        for (int i = 0; i < 2 * n; ++i) {
            totalCycleLength += cycleLengths[i];
        }
        if (totalCycleLength > s) return false;

        // Sort the array using the minimum number of operations
        sort(a.begin(), a.end());

        // Check if the array is sorted after applying the operations
        for (int i = 0; i < n; ++i) {
            if (a[i] != i + 1) return false;
        }

        return true;
    }

    int q;
    cin >> q;
    for (int i = 0; i < q; ++i) {
        int cycleLength;
        cin >> cycleLength;
        vector<int> cycle(cycleLength);
        for (int j = 0; j < cycleLength; ++j) cin >> cycle[j];

        // Apply the operations
        for (int i = 0; i < cycleLength; ++i) {
            int index = cycle[i];
            while (index != i) {
                swap(a[index], a[index - 1]);
                index = a[index - 1];
            }
        }

        // Print the result
        cout << (canSort(a, s) ? "1" : "-1") << endl;
    }

    return 0;
}
