int mergeSort(int arr[], int l, int r, int k) {
    if (l == r) return 0;
    int mid = l + (r - l) / 2;
    int inversions = mergeSort(arr, l, mid, k);
    inversions += mergeSort(arr, mid + 1, r, k);
    inversions += merge(arr, l, mid, k);
    inversions += merge(arr, mid + 1, r, k);
    return inversions;
