int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int t;
    cin >> t;
    while(t--) {
        int n, l, r;
        cin >> n >> l >> r;
        vector<vector<int>> adj(n);
        for(int i = 0; i < n; ++i) {
            for(int j = 0; j < n; ++j) {
                if(i != j && adj[i].size() == 0) {
                    adj[i].push_back(j);
                    adj[j].push_back(i);
                }
            }
        }
        vector<int> visited(n, false);
        vector<int> cycle;
        dfs(adj, visited, cycle, l, r);
        sort(cycle.begin(), cycle.end());
        cout << cycle[l-1] << " " << cycle[l] << " " << cycle[l+1] << " " << cycle[r-1] << " " << cycle[r] << " " << cycle[r+1] << endl;
    }
    return 0;
}

void dfs(vector<vector<int>>& adj, vector<bool>& visited, vector<int>& cycle, int l, int r) {
    if(l > r) return;
    if(visited[l]) return;
    visited[l] = true;
    cycle.push_back(l);
    for(int i = 0; i < adj[l].size(); ++i) {
        if(!visited[adj[l][i]]) {
            dfs(adj, visited, cycle, adj[l][i], r);
        }
    }
    cycle.pop_back();
}
