    int n, k;
    cin >> n >> k;
    vector<vector<int>> books(n, vector<int>(3));
    for (int i = 0; i < n; ++i) {
        cin >> books[i][0] >> books[i][1] >> books[i][2];
    }

    // Sort books by time in ascending order
    sort(books.begin(), books.end(), [](const vector<int>& a, const vector<int>& b) {
        return a[0] < b[0];
    });

    int min_time = INT_MAX;
    vector<int> selected_books;

    // Iterate through sorted books to find the optimal subset
    for (int i = 0; i < n; ++i) {
        if (books[i][2] == 1 && selected_books.empty()) {
            selected_books.push_back(i);
            min_time = min(min_time, books[i][0]);
        } else if (books[i][2] == 1 && !selected_books.empty() && books[i][0] + selected_books[selected_books.size() - 1][0] <= min_time) {
            selected_books.push_back(i);
            min_time = min(min_time, books[i][0] + selected_books[selected_books.size() - 1][0]);
        }
    }

    if (selected_books.empty()) {
        cout << -1 << endl;
    } else {
        int total_time = 0;
        for (int i = 0; i < selected_books.size(); ++i) {
            total_time += books[selected_books[i]][0];
        }
        cout << total_time << endl;
    }

    return 0;
}
