    vector<int> rowSum(r1 + 1, 0);
    vector<int> colSum(c1 + 1, 0);
    vector<int> mainDiagSum(2 * r1 - 1, 0);
    vector<int> sideDiagSum(2 * c1 - 1, 0);

    for (int i = 1; i <= r1; ++i) {
        rowSum[i] += i;
    }
    for (int i = 1; i <= c1; ++i) {
        colSum[i] += i;
    }
    for (int i = 1; i <= r1; ++i) {
        mainDiagSum[i] += i;
    }
    for (int i = 1; i <= c1; ++i) {
        sideDiagSum[i] += i;
    }

