    for (int i = 1; i <= r1; ++i) {
        for (int j = 1; j <= c1; ++j) {
            if (rowSum[i] == d1 && colSum[j] == d2 && mainDiagSum[i + j - 1] == d1 && sideDiagSum[i - j + 1] == d2) {
                foundSolution = true;
                break;
            }
        }
        if (foundSolution) {
            break;
        }
    }

