    cin >> text;

    // Split the text into words
    vector<string> words;
    stringstream ss(text);
    string word;
    while (getline(ss, word, ' ')) {
        words.push_back(word);
    }

    // Find the longest common prefix
    string prefix = "";
    for (int i = 0; i < min(r, words[0].size()); ++i) {
        if (words[0][i] != words[i][i]) {
            prefix = words[0].substr(0, i);
            break;
        }
    }

    // Find the longest common suffix
    string suffix = "";
    for (int i = words.size() - 1; i >= 0; --i) {
        if (words[i][i] != words[i][0]) {
            suffix = words[i].substr(i);
            break;
        }
    }

    // Adjust the prefix and suffix to match the required length
    if (prefix.size() < r) {
        prefix = prefix + string(r - prefix.size(), ' ');
    }
    if (suffix.size() < c) {
        suffix = suffix + string(c - suffix.size(), ' ');
    }

    // Print the result
    for (int i = 0; i < r; ++i) {
        cout << prefix;
        for (int j = 0; j < c; ++j) {
            cout << words[i][j];
        }
        cout << endl;
    }

    return 0;
}
