            free_blocks.erase(remove(free_blocks.begin(), free_blocks.end(), block_id), free_blocks.end());
        } else if (op == 3) {
            cout << mem[free_blocks.front()] << endl;
            free_blocks.erase(free_blocks.begin());
        }
    }

    return 0;
}
