        return a.first > b.first;
    });

    // Sort marg by weight in descending order
    std::sort(marg.begin(), marg.end(), [](const auto& a, const auto& b) {
        return a.first > b.first;
    });

    int total_weight_bocco = 0;
    int total_weight_marg = 0;

    // Calculate the total weight of collected Aidunium
    for (const auto& b : bocco_aidunium) {
        total_weight_bocco += b.first * b.second;
    }

    // Calculate the total weight of regenerated Aidunium
    for (const auto& m : marg) {
        total_weight_marg += m.first * m.second;
    }

    // Find the minimum number of regenerated Aidunium lumps
    int min_lumps = std::max(total_weight_bocco, total_weight_marg);

    // Output the result
    std::cout << min_lumps << " " << min_lumps << std::endl;

