int maxLeaves(int n, int k, vector<int>& p) {
    vector<vector<int>> adj(n + 1);
    for (int i = 1; i <= n; ++i)
        adj[i].push_back(p[i - 1]);

    queue<int> q;
    q.push(1);
    int visited[n + 1];
    memset(visited, 0, sizeof(visited));
    visited[1] = 1;

    int ans = 0;
    while (!q.empty()) {
        int size = q.size();
        for (int i = 0; i < size; ++i) {
            int node = q.front();
            q.pop();

            for (int child : adj[node]) {
                if (visited[child] == 0) {
                    visited[child] = 1;
                    q.push(child);
                    ans++;
                }
            }
        }
    }

    return ans;
}

int main() {
    int n, k;
    cin >> n >> k;
    vector<int> p(n + 1);
    for (int i = 1; i <= n; ++i)
        cin >> p[i];

    cout << maxLeaves(n, k, p) << endl;
    return 0;
}
