    cin >> m >> n;
    vector<vector<int>> program(m, vector<int>(n));
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            cin >> program[i][j];
        }
    }

    int bp = 0, dp = 0, cp = 0;
    while (n--) {
        int maxEdge = 0;
        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                if (program[i][j] > maxEdge) {
                    maxEdge = program[i][j];
                }
            }
        }

        int farthest = maxEdge;
        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                if (program[i][j] == farthest) {
                    bp = i;
                    dp = j;
                    break;
                }
            }
        }

        int nextPixel = bp + (dp - dp % 9);
        if (nextPixel >= m || nextPixel < 0 || nextPixel >= n || program[nextPixel][dp] == 0) {
            bp = dp;
            continue;
        }

        if (program[nextPixel][dp] == program[bp][dp]) {
            bp = nextPixel;
        } else if (program[nextPixel][dp] == program[bp][dp] + 1) {
            bp = nextPixel;
        } else if (program[nextPixel][dp] == program[bp][dp] - 1) {
            bp = nextPixel;
        } else {
            bp = nextPixel;
        }

        if (cp == 0) {
            cp = dp;
        } else if (cp == dp) {
            cp = (dp + 90) % 90;
        } else if (cp == (dp - 90) % 90) {
            cp = (dp + 180) % 90;
        } else {
            cp = (dp - 180) % 90;
        }

        n--;
    }

    cout << program[bp][dp];
