        // we can form a subarray with at least 2 different values.
        if (freqMap[num] >= maxFreq - 1) {
            maxLength = std::max(maxLength, i - j + 1);
        }
    }

    return maxLength;
}

int main() {
    int n;
    std::cin >> n;
    std::vector<int> arr(n);

    for (int i = 0; i < n; ++i) {
        std::cin >> arr[i];
    }

    int result = maxUniqueFrequentSubarray(arr);
    std::cout << result << std::endl;

    return 0;
}
```

This solution works as follows:

1. We use an unordered map to count the frequency of each element in the array.
2. We iterate through the array, updating the frequency map and checking if the frequency of the current element is greater than or equal to `maxFreq - 1`.
3. If the condition is met, we calculate the length of the subarray ending at index `i` and update the maximum length found so far.
4. Finally, we print the maximum length found.

