std::string rearrangeString(const std::string& s, int k) {
    // Count the frequency of each character in the string
    std::vector<int> freq(26, 0);
    for (char c : s) {
        freq[c - 'a']++;
    }

    // Sort the characters by frequency in descending order
    std::sort(freq.begin(), freq.end(), std::greater<int>());

    // Create a new string to store the rearranged characters
    std::string result;
    int count = 0;

    // Distribute characters based on their frequency
    for (int i = 0; i < 26; ++i) {
        while (freq[i] > 0) {
            result += static_cast<char>('a' + i);
            --freq[i];
            count++;
            if (count == k) {
                break;
            }
        }
    }

    // If no valid k-string was found, return -1
    if (count != k) {
        return "-1";
    }

    return result;
}

int main() {
    int k;
    std::cin >> k;
    std::string s;
    std::cin >> s;

    std::string result = rearrangeString(s, k);
