    std::unordered_map<std::string, int> personToMessages;
    int outgoingTraffic = 0;

    for (const auto& command : input) {
        std::istringstream iss(command);
        std::string name;
        std::string messageText;

        iss >> name >> messageText;

        if (name == "+") {
            personToMessages[name]++;
        } else if (name == "-") {
            personToMessages.erase(name);
        } else if (name != "") {
            outgoingTraffic += messageText.length();
        }
    }

    return outgoingTraffic;
}

