#include <iostream>
#include <vector>
#include <algorithm>
#include <unordered_map>
#include <limits>

using namespace std;

int main() {
    int n, k;
    cin >> n >> k;

    // Create an adjacency list representation of the graph
    vector<vector<int>> adj(n);
    for (int i = 0; i < k; ++i) {
        int a, b;
        cin >> a >> b;
        adj[a - 1].push_back(b - 1);
        adj[b - 1].push_back(a - 1);
    }

    // Function to perform DFS and find paths
    function<void(int, vector<int>&, vector<int>&)> dfs = [&](int node, vector<int>& path, vector<int>& visited) {
        if (visited[node]) return;

        // Add the current node to the path
        path.push_back(node);

        // If the path length is 2n - 2, print the path
        if (path.size() == 2 * n - 2) {
            cout << path[0] << " " << path[1] << endl;
            return;
        }

        // Mark the current node as visited
        visited[node] = true;

        // Recursively visit all adjacent nodes
        for (int neighbor : adj[node]) {
            dfs(neighbor, path, visited);
        }

        // Backtrack by removing the current node from the path
        path.pop_back();
    };

    // Check if there are enough roads to form paths
    if (k > n - 1) {
        cout << -1 << endl;
        return 0;
    }

    // Initialize visited array
    vector<bool> visited(n, false);

    // Start DFS from each city
    for (int i = 0; i < n; ++i) {
        dfs(i, {i}, visited);
    }

    return 0;
}
```

This solution reads the number of cities `n` and the maximum allowed number of roads `k`. It then creates an adjacency list representation of the graph. The `dfs` function performs a depth-first search starting from each city, adding paths to the result vector. If the path length reaches `2n - 2`, it prints the path. The solution checks if there are enough roads to form paths and returns `-1` if not.

