    // Calculate the angle between the vectors (b - a) and (c - b)
    double x = b - a;
    double y = c - b;
    double dotProduct = x * y;
    double magnitudeAB = sqrt(x * x + y * y);
    double magnitudeBC = sqrt(b * b + c * c);
    double cosineAngle = dotProduct / (magnitudeAB * magnitudeBC);

    // Check if the angle is between 0 and 90 degrees
    if (cosineAngle >= 0 && cosineAngle <= 90) {
        cout << "Yes" << endl;
    } else {
        cout << "No" << endl;
    }

    return 0;
}
