// Function to calculate the minimum sum of square quantization errors
double minSumOfSquareQuantizationErrors(const std::vector<double>& data, int N, int M, int L) {
    double minError = std::numeric_limits<double>::max();
    for (int i = 0; i < N; ++i) {
        double quantizedValue = calculateQuantizedValue(data[i], M, L);
        double error = std::pow(quantizedValue - data[i], 2);
        if (error < minError) {
            minError = error;
        }
    }
    return minError;
}

// Function to calculate the quantized value
double calculateQuantizedValue(double value, int M, int L) {
    double maxVal = std::max(value, 0.0);
    double minVal = std::min(value, 1.0);
    double quantizedValue = (maxVal - minVal) / (2 * L - 1);
    return quantizedValue;
}

int main() {
    int N, M, L;
    std::cin >> N >> M >> L;

    std::vector<double> data(N);
    for (int i = 0; i < N; ++i) {
        std::cin >> data[i];
    }

    double minError = minSumOfSquareQuantizationErrors(data, N, M, L);

    std::cout << minError << std::endl;

    return 0;
}
