    for (int i = 0; i < n; ++i) {
        cin >> arrows[i][0] >> arrows[i][1] >> arrows[i][2] >> arrows[i][3];
    }
    int q;
    cin >> q;
    vector<vector<int>> plans(q);
    for (int i = 0; i < q; ++i) {
        int xi, yi, wi, ti;
        cin >> xi >> yi >> wi >> ti;
        plans[i] = {xi, yi, wi, ti};
    }

