    auto closestArrow = [&](int x, int y) -> pair<int, int> {
        int minDist = INT_MAX;
        pair<int, int> closest;
        for (int i = 0; i < n; ++i) {
            int dx = abs(x - arrows[i][0]);
            int dy = abs(y - arrows[i][1]);
            int dist = dx + dy;
            if (dist < minDist) {
                minDist = dist;
                closest = {arrows[i][0], arrows[i][1]};
            }
        }
        return closest;
    };

    // Main loop to simulate the Beaveractor's journey
    for (int i = 0; i < q; ++i) {
        int x, y, wi, ti;
        cin >> x >> y >> wi >> ti;
        int closestX, closestY;
        closestX = closestArrow(x, y)[0];
        closestY = closestArrow(x, y)[1];

        // Move the Beaveractor towards the closest arrow
        while (ti > 0 && closestX <= x && closestY <= y) {
            ti--;
            x += wi;
            y += wi;
        }

        // Print the final coordinates of the Beaveractor
        cout << x << " " << y << endl;
    }

    return 0;
}
