    }

    // Create a copy of the original maze
    vector<vector<char>> new_maze(maze);

    // Add walls to make the maze connected
    for (int i = 0; i < empty_count; ++i) {
        int x = rand() % n;
        int y = rand() % m;
        while (new_maze[x][y] == '#') {
            x = rand() % n;
            y = rand() % m;
        }
        new_maze[x][y] = '#';
    }

    // Print the new maze
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            cout << new_maze[i][j];
        }
        cout << endl;
    }

    return 0;
}
