double clearSnowArea(int n, vector<vector<int>>& points) {
    double totalSnow = 0;
    for (int i = 0; i < n; ++i) {
        int x1 = points[i][0], y1 = points[i][1];
        int x2 = points[(i + 1) % n][0], y2 = points[(i + 1) % n][1];
        double distance = sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
        totalSnow += distance;
    }
    return totalSnow;
}

