        visited[node] = 1;
        for (auto neighbor : adj[node]) {
            if (!visited[neighbor]) {
                if (dfs(neighbor)) {
                    centroid[node] = 1;
                    return true;
                }
            }
        }
        return false;
    };

    for (int i = 0; i < n; ++i) {
        if (centroid[i] == 0 && !dfs(i)) {
            centroid[i] = 1;
        }
    }

