    for (int i = 0; i < n; ++i) {
        if (visited[i]) continue;

        int currentVolume = x[i];
        int jumps = 0;

        while (currentVolume > 0) {
            if (currentVolume % 2 == 0) {
                // Jump to the next oasis
                currentVolume /= 2;
                jumps++;
            } else {
                // Water from the current oasis
                currentVolume -= v;
                jumps++;
            }

            if (jumps > n) break;
        }

        if (jumps == n) {
            cout << "Possible" << endl;
        } else {
            cout << "Impossible" << endl;
        }
    }

    return 0;
}
