double maxSkinArea(int a, int l, int x) {
    double area = 0;
    double maxArea = 0;

    // Calculate the area of triangle ABC
    double s = (a + l + x) / 2;
    area = std::sqrt(s * (s - a) * (s - l) * (s - x));

    // Calculate the area of triangle ADC and BEC
    double areaADC = (a * l + l * x + x * a) / 2;
    double areaBEC = (a * x + x * l + l * a) / 2;

    // Calculate the sum of the areas of triangle ADC and BEC
    double sumADC = areaADC + areaBEC;

    // Calculate the maximum area
    if (sumADC > maxArea) {
        maxArea = sumADC;
    }

    return maxArea;
}

