std::string inferMessage(const std::vector<std::string>& orders, const std::string& message) {
    std::string originalMessage = message;
    for (const auto& order : orders) {
        std::string reversedOrder = order;
        std::reverse(reversedOrder.begin(), reversedOrder.end());
        std::string transformedMessage = "";
        for (size_t i = 0; i < message.length(); ++i) {
            if (message[i] == 'a') {
                transformedMessage += reversedOrder[i];
            } else if (message[i] == 'b') {
                transformedMessage += reversedOrder[i + 1];
            } else if (message[i] == 'c') {
                transformedMessage += reversedOrder[i + 2];
            } else if (message[i] == 'd') {
                transformedMessage += reversedOrder[i + 3];
            } else if (message[i] == 'e') {
                transformedMessage += reversedOrder[i + 4];
            } else if (message[i] == 'f') {
                transformedMessage += reversedOrder[i + 5];
            }
        }
        originalMessage = transformedMessage;
    }
    return originalMessage;
}

int main() {
    int n;
    std::cin >> n;
    std::vector<std::string> orders(n);
    std::string message;
    for (int i = 0; i < n; ++i) {
        std::cin >> orders[i];
        std::cin >> message;
    }

    std::string inferredMessage = inferMessage(orders, message);
    std::cout << inferredMessage << std::endl;

    return 0;
}
