using namespace std;

int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

bool is_pairwise_coprime(vector<int>& A) {
    int n = A.size();
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (gcd(A[i], A[j]) != 1) {
                return false;
            }
        }
    }
    return true;
}

bool is_setwise_coprime(vector<int>& A) {
    int n = A.size();
    for (int i = 0; i < n; ++i) {
        if (gcd(A[i], A[0]) != 1) {
            return false;
        }
    }
    return true;
}

int main() {
    int N;
    cin >> N;
    vector<int> A(N);
    for (int i = 0; i < N; ++i) {
        cin >> A[i];
    }

    if (is_pairwise_coprime(A)) {
        cout << "pairwise coprime" << endl;
    } else if (is_setwise_coprime(A)) {
        cout << "setwise coprime" << endl;
    } else {
        cout << "not coprime" << endl;
    }

    return 0;
}
