bool isMirrorString(const std::string& s) {
    std::string reversed = s;
    std::reverse(reversed.begin(), reversed.end());

    for (char c : s) {
        if (c == 'b') {
            c = 'd';
        } else if (c == 'd') {
            c = 'b';
        } else if (c == 'p') {
            c = 'q';
        } else if (c == 'q') {
            c = 'p';
        }
    }

    return reversed == s;
}

