typedef long long ll;
const int mod = 1e9 + 7;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int n, m;
    cin >> n >> m;
    vector<vector<ll>> dp(n + 1, vector<ll>(m + 1, 0));
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= m; ++j) {
            if (i == 1 && j == 1) {
                dp[i][j] = 1;
            } else if (i == 1) {
                dp[i][j] = dp[i][j - 1];
            } else if (j == 1) {
                dp[i][j] = dp[i - 1][j];
            } else {
                dp[i][j] = (dp[i - 1][j] + dp[i][j - 1]) % mod;
                dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % mod;
            }
        }
    }
    ll ans = 0;
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= m; ++j) {
            if (dp[i][j] == 1) {
                ans = (ans + dp[i - 1][j]) % mod;
            }
        }
    }
    cout << ans << endl;
    return 0;
}
