int minStepsToMoveCenter(int r, int x, int y, int x', int y') {
    // Calculate the distance between the original center and the destination center
    int dx = abs(x - x');
    int dy = abs(y - y');

    // If the distance is less than or equal to the radius, no steps are needed
    if (dx <= r && dy <= r) {
        return 0;
    }

    // Calculate the angle between the original center and the destination center
    double angle = atan2(dy, dx);

    // Calculate the number of steps required to move the center to the destination point
    int steps = (int)(angle * 180 / M_PI);

    return steps;
}
