typedef long long ll;

int mod = 1e9 + 7;

int main() {
    int n, m;
    cin >> n >> m;
    vector<vector<int>> mat(n, vector<int>(m));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            cin >> mat[i][j];
        }
    }

    int dp[n][m];
    memset(dp, 0, sizeof(dp));

    // Base case: one way to reach (2, 1)
    dp[2][1] = 1;

    // Fill the DP table
    for (int i = 2; i < n; ++i) {
        for (int j = 2; j < m; ++j) {
            // Check all possible moves
            if (mat[i - 1][j + 1] > 0) {
                dp[i][j] = (dp[i][j] + dp[i - 1][j + 1]) % mod;
            }
            if (mat[i][j + 1] > 0) {
                dp[i][j] = (dp[i][j] + dp[i][j + 1]) % mod;
            }
            if (mat[i + 1][j + 1] > 0) {
                dp[i][j] = (dp[i][j] + dp[i + 1][j + 1]) % mod;
            }
        }
    }

    // Output the result
    cout << dp[n - 1][m - 1] << endl;
    return 0;
}
