            if (tetrahedral_sum > num) {
                break;
            }
            min_tetrahedral += i;
        }

        // Find the minimum number of odd tetrahedral numbers needed
        for (int i = 1; i <= num; i += 2) {
            int odd_tetrahedral_sum = i * (i + 1) / 2;
            if (odd_tetrahedral_sum > num) {
                break;
            }
            min_odd_tetrahedral += i;
        }

        results.push_back({min_tetrahedral, min_odd_tetrahedral});
    }

    for (const auto& result : results) {
        std::cout << result.first << " " << result.second << std::endl;
    }

    return 0;
}
