#include <bits/stdc++.h>
using namespace std;

int maxArea(vector<vector<int>>& matrix) {
    int H = matrix.size(), W = matrix[0].size();
    vector<vector<int>> dp(H + 1, vector<int>(W + 1, 0));

    for (int i = 1; i <= H; ++i) {
        for (int j = 1; j <= W; ++j) {
            if (matrix[i - 1][j - 1] == 0) {
                dp[i][j] = dp[i - 1][j] + dp[i][j - 1];
            } else {
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]) + 1;
            }
        }
    }

    int maxArea = 0;
    for (int i = 1; i <= H; ++i) {
        for (int j = 1; j <= W; ++j) {
            maxArea = max(maxArea, dp[i][j]);
        }
    }

    return maxArea;
}
