        for (int j = 0; j < n; ++j) {
            if (a[j] > lis.back()) lis.push_back(a[j]);
        }

        // Find the longest decreasing subsequence (LSD)
        vector<int> lsd;
        for (int j = n - 1; j >= 0; --j) {
            if (a[j] < lsd.back()) lsd.push_back(a[j]);
        }

        // Check if there is a subsequence of length greater than 2
        if (lsis.size() >= 3 && lsd.size() >= 3) {
            int max_len = max(lis.size(), lsd.size());
            for (int j = 0; j < max_len; ++j) {
                if (lis[j] == lsd[j]) {
                    cout << 0 << endl;
                    return 0;
                }
            }
        }

        // Output the length of the longest subsequence
        cout << max_len << endl;

        // Output the indices of the longest subsequence
        for (int j = 0; j < max_len; ++j) {
            cout << lis[j] << " ";
        }
        cout << endl;
