            if (current_count > 1) {
                break;
            }
            // Add the current number to the result
            max_count = std::max(max_count, current_count + 1);
            current_count = 0;
        }
    }

    // If there were no 0s, add the last 0 to the result
    if (current_count > 1) {
        max_count = std::max(max_count, current_count + 1);
    }

    // Output the result
    std::cout << max_count << std::endl;
    for (int num : d) {
