using namespace std;

int minEdgesToRemove(int N, int M, vector<int>& X, vector<int>& A, vector<int>& B, vector<int>& Y) {
    // Create an adjacency list representation of the graph
    vector<vector<int>> adj(N + 1);
    for (int i = 0; i < M; ++i) {
        adj[A[i]].push_back(B[i]);
        adj[B[i]].push_back(A[i]);
    }

    // Function to perform DFS and calculate the sum of weights in the connected component
    int dfs(int u, vector<int>& visited, int& sum) {
        if (visited[u]) return 0;
        visited[u] = 1;
        int ans = 0;
        for (int v : adj[u]) {
            ans += dfs(v, visited, sum);
        }
        sum += X[u];
        return ans;
    }

    // Find the minimum number of edges to remove
    int minEdges = INT_MAX;
    for (int i = 1; i <= N; ++i) {
        if (!visited[i]) {
            int sum = 0;
            int edgesToRemove = dfs(i, visited, sum);
            minEdges = min(minEdges, edgesToRemove);
        }
    }

    return minEdges;
}

int main() {
    int N, M;
    cin >> N >> M;
    vector<int> X(N + 1), A(M), B(M), Y(M);

    for (int i = 0; i < M; ++i) {
        cin >> X[i];
        cin >> A[i];
        cin >> B[i];
    }

    cout << minEdgesToRemove(N, M, X, A, B, Y) << endl;
