        for(int j=i+1;j<n;j++){
            if(P[i]==P[j]){
                adj[i].push_back(j);
                adj[j].push_back(i);
            }
        }
    }
    vector<int> color(n,0);
    vector<ll> weight(n,0);
    queue<int> q;
    q.push(0);
    while(!q.empty()){
        int node=q.front();
        q.pop();
        color[node]=1;
        weight[node]=X[node];
        for(auto child:adj[node]){
