        A = std::max(A, data[i][2]);
        B = std::max(B, data[i][3]);
        A_intersect_B = std::max(A_intersect_B, data[i][4]);
    }

    double area_A = static_cast<double>(A);
    double area_B = static_cast<double>(B);
    double area_intersect = static_cast<double>(A_intersect_B);

    double min_area = std::min(area_A, area_B);
    double max_area = std::max(area_A, area_B);

    if (min_area > 0.0001 || max_area > 0.0001) {
        std::cout << "impossible" << std::endl;
