        double x_A = (U_W - area_intersect) / 2.0;
        double y_A = (U_H - area_intersect) / 2.0;
        double x_B = (U_W + area_intersect) / 2.0;
        double y_B = (U_H + area_intersect) / 2.0;

        std::cout << x_A << " " << y_A << " " << std::sqrt(min_area) << " " << x_B << " " << y_B << " " << std::sqrt(max_area) << std::endl;
