std::pair<int, int> findMaxZeroesSum(int n) {
    std::vector<int> digits;
    while (n > 0) {
        digits.push_back(n % 10);
        n /= 10;
    }

    std::sort(digits.begin(), digits.end());

    int maxZeroes = 0;
    for (int i = 0; i < digits.size(); ++i) {
        int zeroCount = 0;
        for (int j = 0; j < digits.size(); ++j) {
            if (digits[j] == 0) {
                zeroCount++;
            }
        }
        if (zeroCount > maxZeroes) {
            maxZeroes = zeroCount;
            std::swap(digits[i], digits[0]);
        }
    }

    return {digits[0], digits[digits.size() - 1]};
}

int main() {
    int n;
    std::cin >> n;

    auto result = findMaxZeroesSum(n);
    std::cout << result.first << " " << result.second << std::endl;

    return 0;
}
```

This solution reads a positive integer `n` from standard input, converts it to a vector of its digits, sorts them, and then iterates through the sorted digits to find the pair of digits that has the maximum number of zeroes when summed. The main function handles the input and outputs the result.

