std::vector<int> beautifulPermutation(int n) {
    std::vector<int> result(n);
    std::vector<int> p = {1, 2, ..., n};
    int k = 2;
    while (true) {
        int r = n % k;
        if (r == 0) {
            break;
        }
        for (int i = 0; i < k; ++i) {
            result[i] = p[i];
        }
        for (int i = k; i < n; ++i) {
            result[i] = p[(i - k + k) % k];
        }
        k = r;
    }
    return result;
}

int main() {
