std::string findLongestPalindrome(const std::string& s) {
    int n = s.length();
    std::vector<int> dp(n, 1);
    for (int i = 1; i < n; ++i) {
        if (s[i] == s[i - 1]) {
            dp[i] = dp[i - 1] + 2;
        } else {
            dp[i] = std::max(dp[i - 1], dp[i]);
        }
    }

    int maxLen = 0;
    for (int i = 0; i < n; ++i) {
        if (dp[i] > maxLen) {
            maxLen = dp[i];
        }
    }

    std::string result;
    int left = 0;
    int right = n - 1;
    while (left < right) {
        if (s[left] == s[right]) {
            result += s[left];
            ++left;
            --right;
        } else {
            if (dp[left] > dp[right]) {
                result += s[left++];
            } else {
                result += s[right--];
            }
        }
    }

    return result;
}

int main() {
    std::string s;
    std::cin >> s;

    std::string longestPalindrome = findLongestPalindrome(s);

    std::cout << longestPalindrome << std::endl;

    return 0;
