        for (int i = 0; i < n; ++i) {
            if (roads[node][i] && distances[i] > dist + 1) {
                distances[i] = dist + 1;
                pq.push({dist + 1, i});
            }
        }
    }
    vector<int> result;
    for (int i = 0; i < n; ++i) {
        if (distances[i] == INT_MAX) {
            result.push_back(-1);
        } else {
            result.push_back(i + 1);
