#include <iostream>
#include <vector>
#include <algorithm>

int minExchanges(int n, std::vector<int>& a, std::vector<int>& b) {
    // Sort the arrays to facilitate finding the minimum number of exchanges
    std::sort(a.begin(), a.end());
    std::sort(b.begin(), b.end());

    int exchanges = 0;
    int i = 0, j = 0;

    while (i < n && j < n) {
        // If the current students have the same performance, increment the exchange count
        if (a[i] == b[j]) {
            ++exchanges;
            ++i;
            ++j;
        } else {
            // If the current students have different performances, find the closest pair
            int closestPair = std::min(a[i], b[j]);
            int index = std::lower_bound(a.begin(), a.end(), closestPair) - a.begin();
            int nextIndex = std::upper_bound(b.begin(), b.end(), closestPair) - b.begin();

            // If the next index is within the bounds of the array, increment the exchange count
            if (nextIndex < n) {
                ++exchanges;
                ++i;
                ++j;
            } else {
                // If the next index is out of bounds, break the loop
                break;
            }
        }
    }

    return exchanges;
}

int main() {
    int n;
    std::cin >> n;

    std::vector<int> a(n);
    std::vector<int> b(n);

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        std::cin >> b[i];
    }

    int result = minExchanges(n, a, b);

    if (result == -1) {
        std::cout << -1 << std::endl;
    } else {
        std::cout << result << std::endl;
    }

    return 0;
}
