#include <iostream>
#include <string>
#include <algorithm>

std::string shortestCommonNonSubsequence(const std::string& seq1, const std::string& seq2) {
    int m = seq1.length(), n = seq2.length();
    std::vector<int> dp(m + 1, 0);
    std::vector<int> prev(m + 1, 0);

    for (int i = 1; i <= m; ++i) {
        for (int j = 1; j <= n; ++j) {
            if (seq1[i - 1] == seq2[j - 1]) {
                dp[i] = dp[i - 1] + 1;
                prev[i] = j;
            } else {
                dp[i] = std::max(dp[i - 1], dp[i]);
            }
        }
    }

    std::string result;
    int i = m, j = n;
    while (i > 0 && j > 0) {
        if (seq1[i - 1] == seq2[j - 1]) {
            result.push_back('0');
            --i;
            --j;
        } else if (dp[i - 1] > dp[j - 1]) {
            result.push_back('1');
            --i;
        } else {
            result.push_back('0');
            --j;
        }
    }

    std::reverse(result.begin(), result.end());
    return result;
}

int main() {
    std::string seq1, seq2;
    std::cin >> seq1 >> seq2;

    std::string result = shortestCommonNonSubsequence(seq1, seq2);
    std::cout << result << std::endl;

    return 0;
}
```

This solution uses dynamic programming to find the shortest common non-subsequence of two sequences. It iterates through each character of the sequences, updating the DP table to keep track of the longest common subsequence found so far. The result is then reversed to get the correct order.

