        cout << "NO" << endl;
        return 0;
    }

    // Find the number of unique elements in the matrix
    unordered_set<int> unique_elements(matrix.begin(), matrix.end());
    int num_unique_elements = unique_elements.size();

    // If the number of unique elements is less than n^2, return "YES"
