    // Check if the last student can start a clockwise round dance
    if (p[n-1] == n) return true;

    // Check if the second student can start a counterclockwise round dance
    if (p[1] == 2) return true;

    // Check if the third student can start a counterclockwise round dance
    if (p[2] == 3) return true;

    // Check if the fourth student can start a counterclockwise round dance
    if (p[3] == 4) return true;

    return false;
