        monstries[monstries.size() - 1 - i] = i + 1;
    }
    vector<vector<int>> graph(n);
    for (int i = 0; i < m; ++i) {
        int a = monstries[monstries.size() - 1 - i];
        int b = monstries[i];
        graph[a].push_back(b);
        graph[b].push_back(a);
    }
    int max_unhappy = 0;
    int ways_to_make_unhappy = 0;
    for (int i = 0; i < n; ++i) {
        vector<bool> visited(n, false);
        queue<int> q;
        q.push(i);
        visited[i] = true;
        while (!q.empty()) {
            int current = q.front();
            q.pop();
            for (int neighbor : graph[current]) {
                if (!visited[neighbor]) {
                    visited[neighbor] = true;
                    q.push(neighbor);
                }
            }
            if (visited[current]) {
                ++max_unhappy;
            }
        }
        if (max_unhappy > 1) {
            ways_to_make_unhappy++;
        }
    }
    cout << max_unhappy << " " << ways_to_make_unhappy;
    return 0;
