int main() {
    string s;
    cin >> s;

    int n = s.size();
    vector<vector<char>> grid(n, vector<char>(n));

    // Create the grid based on the input string
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            grid[i][j] = s[i * n + j];
        }
    }

    // Function to check if a path exists
    bool hasPath(vector<vector<char>>& grid, int x, int y, int dir) {
        int nx = x + dir;
        int ny = y + dir;
        while (nx >= 0 && nx < n && ny >= 0 && ny < n && grid[nx][ny] == grid[x][y]) {
            nx += dir;
            ny += dir;
        }
        return nx == n - 1 && ny == n - 1;
    }

    // Try all possible paths from each cell
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            if (hasPath(grid, i, j, 0)) {
                vector<char> path;
                path.push_back(grid[i][j]);
                for (int k = 1; k < n; ++k) {
                    if (hasPath(grid, i, j, k)) {
                        path.push_back(grid[i][j + k]);
                    }
                }
                cout << path[0] << endl;
                return 0;
            }
        }
    }

    cout << "Impossible" << endl;
    return 0;
}
