double calculateProbability(const std::string& s) {
    int n = s.length();
    int k = rand() % n;
    std::string t = s.substr(k) + s.substr(0, k);
    int count = 0;

    // Check all possible cyclic shifts of t
    for (int i = 0; i < n; ++i) {
        std::string shifted = t.substr(i) + t.substr(0, i);
        if (shifted == s) {
            ++count;
        }
    }

    return static_cast<double>(count) / n;
}

int main() {
    std::string input;
    std::cin >> input;

    double probability = calculateProbability(input);

    std::cout << probability << std::endl;

    return 0;
}
