#include <iostream>
#include <vector>
#include <string>

int minSecondsToMove(const std::string& battlefield, const std::string& gesotaPosition, const std::string& targetPosition) {
    int R = battlefield.size();
    int C = battlefield[0].size();

    // Read the battlefield information
    std::vector<std::vector<char>> battlefieldGrid(R, std::vector<char>(C));
    for (int i = 0; i < R; ++i) {
        for (int j = 0; j < C; ++j) {
            battlefieldGrid[i][j] = battlefield[j * R + i];
        }
    }

    // Read the Gesota's position and target position
    int gesotaX = std::stoi(gesotaPosition.substr(0, 1));
    int gesotaY = std::stoi(gesotaPosition.substr(1, 1));
    int targetX = std::stoi(targetPosition.substr(0, 1));
    int targetY = std::stoi(targetPosition.substr(1, 1));

    // Directions for moving
    int dx[] = {0, 1, 0, -1};
    int dy[] = {1, 0, -1, 0};

    // Initialize the queue with Gesota's position
    std::queue<std::pair<int, int>> q;
    q.push({gesotaX, gesotaY});

    // Initialize the distance matrix
    std::vector<std::vector<int>> distanceMatrix(R, std::vector<int>(C, INT_MAX));
    distanceMatrix[gesotaX][gesotaY] = 0;

    // Perform BFS
    while (!q.empty()) {
        int x = q.front().first;
        int y = q.front().second;
        q.pop();

        // Explore all four directions
        for (int i = 0; i < 4; ++i) {
            int nx = x + dx[i];
            int ny = y + dy[i];

            // Check if the new position is within bounds and not a wall
            if (nx >= 0 && nx < R && ny >= 0 && ny < C && battlefieldGrid[nx][ny] != '#' && distanceMatrix[nx][ny] > distanceMatrix[x][y] + 2) {
                distanceMatrix[nx][ny] = distanceMatrix[x][y] + 2;
                q.push({nx, ny});
            }
        }
    }

    // Calculate the minimum time to move to the target position
    int minTime = INT_MAX;
    for (int i = 0; i < R; ++i) {
        for (int j = 0; j < C; ++j) {
            if (distanceMatrix[i][j] == 0 && battlefieldGrid[i][j] == 'S') {
                minTime = std::min(minTime, distanceMatrix[i][j]);
            }
        }
    }

    return minTime;
}

int main() {
    std::string battlefield;
    std::string gesotaPosition;
    std::string targetPosition;

    std::cout << "Enter the battlefield information: ";
    std::getline(std::cin, battlefield);

    std::cout << "Enter Gesota's position: ";
    std::getline(std::cin, gesotaPosition);

