using namespace std;

bool hasCycle(vector<vector<int>>& G) {
    unordered_map<int, vector<int>> adjList;
    for (int i = 0; i < G.size(); ++i) {
        for (int j = 0; j < G[i].size(); ++j) {
            adjList[G[i][j]].push_back(i);
        }
    }

    for (int i = 0; i < G.size(); ++i) {
        if (visited[i] == true) continue;
        if (dfs(G, i, visited)) return true;
    }
    return false;
}

bool dfs(vector<vector<int>>& G, int node, vector<bool>& visited) {
    visited[node] = true;
    for (int neighbor : adjList[node]) {
        if (!visited[neighbor]) {
            if (dfs(G, neighbor, visited)) return true;
        } else if (neighbor == node) return true;
    }
    return false;
}

int main() {
    int V, E;
    cin >> V >> E;

    vector<vector<int>> G(V, vector<int>(E));
    for (int i = 0; i < E; ++i) {
        int u, v;
        cin >> u >> v;
        G[u][v] = 1;
        G[v][u] = 1;
    }

    if (hasCycle(G)) {
        cout << 1 << endl;
    } else {
        cout << 0 << endl;
    }

    return 0;
}
