    std::vector<bool> seen(n, false);

    // Build the positions of equal letters
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (positions[i][positions[j].size() - 1] == positions[j][positions[i].size() - 1]) {
                positions[i][positions[j].size()] = positions[i].size();
                seen[positions[i].size()] = true;
            }
        }
    }

    // Find the smallest lucky string
    std::string result;
    for (int i = 0; i < n; ++i) {
        if (!seen[i]) {
            result += 'a' + i;
            seen[i] = true;
        }
    }

    return result;
}

int main() {
