    for (int i = 0; i < m; ++i) {
        int u, v;
        std::cin >> u >> v;
        railways.push_back({u, v});
    }

    // Sort the railways by their destination
    std::sort(railways.begin(), railways.end(), [](const auto& a, const auto& b) {
        return a.second < b.second;
    });

    // Initialize variables
    int busArrivalTime = -1;
    int trainArrivalTime = -1;

    // Iterate through the railways
    for (const auto& railway : railways) {
        int u = railway.first;
        int v = railway.second;

        // Check if the bus can reach town n
        if (busArrivalTime == -1 || u != n) {
            busArrivalTime = railway.second;
        }

        // Check if the train can reach town n
        if (trainArrivalTime == -1 || v != n) {
            trainArrivalTime = railway.second;
        }
    }

    // Output the minimum time needed
    if (busArrivalTime != -1 && trainArrivalTime != -1) {
        std::cout << std::min(busArrivalTime, trainArrivalTime);
    } else {
        std::cout << -1;
    }

    return 0;
}
