int maxOccurrences(const std::string& s, const std::string& t) {
    int count = 0;
    std::unordered_map<char, int> charCount;

    // Count the occurrences of each character in string t
    for (char c : t) {
        charCount[c]++;
    }

    // Iterate through string s and replace question marks with characters from t
    for (size_t i = 0; i < s.size(); ++i) {
        if (s[i] == '?') {
            char c = t[charCount[s[i]]];
            if (charCount[c] > 0) {
                s[i] = c;
                --charCount[c];
            }
        }
    }

    // Count the occurrences of string t again
    for (char c : t) {
        charCount[c]++;
    }

    // Calculate the maximum number of occurrences of string t
    for (const auto& pair : charCount) {
        count = std::max(count, pair.second);
    }

    return count;
}

int main() {
    std::string s, t;
    std::cin >> s >> t;

    int result = maxOccurrences(s, t);
    std::cout << result << std::endl;

    return 0;
}
