#include <iostream>
#include <algorithm>
#include <string>
#include <sstream>

std::pair<int, int> findMaxProperIrreducibleFraction(int n) {
    // Start with the smallest possible fraction
    int numerator = 1;
    int denominator = n;

    // Find the largest proper irreducible fraction
    while (true) {
        if (isProper(numerator, denominator)) {
            break;
        }
        ++numerator;
        --denominator;
    }

    return {numerator, denominator};
}

bool isProper(int numerator, int denominator) {
    // Check if the fraction is proper
    return numerator < denominator && gcd(numerator, denominator) == 1;
}

int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    int n;
    std::cin >> n;

    auto [numerator, denominator] = findMaxProperIrreducibleFraction(n);

    std::cout << numerator << " " << denominator << std::endl;

    return 0;
}
```

This code snippet defines a function `findMaxProperIrreducibleFraction` that takes an integer `n` as input and returns a pair of integers representing the numerator and denominator of the maximum possible proper irreducible fraction such that the sum of its numerator and denominator equals `n`. It also includes helper functions `isProper` to check if a fraction is proper and `gcd` to compute the greatest common divisor. The `main` function reads an integer `n`, calls the `findMaxProperIrreducibleFraction` function, and outputs the result.

