        std::cin >> a >> b >> c;
        themes[i].push_back(a);
        themes[i].push_back(b);
        themes[i].push_back(c);
    }

    // Sort the roads by distance
    std::sort(roads.begin(), roads.end(), [](const std::vector<int>& a, const std::vector<int>& b) {
        return a[2] < b[2];
    });

    // Assign themes to cities
    std::vector<int> cityAssignments(N);
    for (int i = 0; i < Q; ++i) {
        int city = themes[i][0];
        cityAssignments[city] = i + 1;
    }

    // Find the meeting city
    int meetingCity = -1;
    for (int i = 0; i < N; ++i) {
        if (cityAssignments[i] == 1) {
            meetingCity = i + 1;
            break;
        }
