int knapsack(vector<vector<int>>& items, int W) {
    // Sort items by weight in descending order
    sort(items.begin(), items.end(), [](const vector<int>& a, const vector<int>& b) {
        return a[1] > b[1];
    });

    int totalValue = 0;
    int currentWeight = 0;

    for (const auto& item : items) {
        if (currentWeight + item[1] <= W) {
            totalValue += item[0];
            currentWeight += item[1];
        }
    }

    return totalValue;
}

