int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int wcd(const std::vector<std::pair<int, int>>& pairs) {
    int result = 1;
    for (const auto& pair : pairs) {
        result = gcd(result, pair.first);
        result = gcd(result, pair.second);
    }
    return result;
}

int main() {
    int n;
    std::cin >> n;
    std::vector<std::pair<int, int>> pairs(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> pairs[i].first >> pairs[i].second;
    }

    int wcd_value = wcd(pairs);
    std::cout << wcd_value << std::endl;

    return 0;
}
