#include <iostream>
#include <vector>
#include <algorithm>

std::string minBracketSequence(const std::string& sequence) {
    std::vector<char> stack;
    int balance = 0;

    for (char ch : sequence) {
        if (ch == '(') {
            stack.push_back(ch);
            balance++;
        } else if (ch == ')') {
            if (balance > 0) {
                balance--;
                stack.pop_back();
            } else {
                // Perform a cyclic shift
                std::reverse(stack.begin(), stack.end());
                balance = 0;
            }
        }
    }

    // If balance is not zero, it means there are unmatched opening brackets
    if (balance != 0) {
        std::reverse(stack.begin(), stack.end());
    }

    // Construct the correct bracket sequence
    std::string result;
    for (char ch : stack) {
        if (ch == '(') {
            result += ')';
        } else {
            result += '(';
        }
    }

    return result;
}

int main() {
    std::string sequence;
    std::cin >> sequence;

    std::string result = minBracketSequence(sequence);

    std::cout << result << std::endl;

    return 0;
}
```

