using namespace std;

int main() {
    int n, m;
    cin >> n >> m;

    vector<vector<int>> matrix(n, vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            cin >> matrix[i][j];
        }
    }

    int operation_count;
    cin >> operation_count;

    for (int i = 0; i < operation_count; ++i) {
        int o;
        cin >> o;

        if (o == 0) {
            // Rotate
            int r, c, size;
            cin >> r >> c >> size;
            int new_r = r + size - 1;
            int new_c = c + size - 1;
            swap(matrix[new_r][new_c], matrix[r][c]);
        } else if (o == 1) {
            // Reversal
            int r, c, size;
            cin >> r >> c >> size;
            reverse(matrix[r][c], matrix[r][c] + size);
        } else if (o == 2) {
            // Left shift
            int r;
            cin >> r;
            int new_r = r;
            for (int i = 0; i < size; ++i) {
                swap(matrix[new_r][i], matrix[new_r][i + 1]);
            }
            matrix[new_r][size - 1] = matrix[r][size - 1];
        } else if (o == 3) {
            // Right shift
            int r;
            cin >> r;
            int new_r = r;
            for (int i = size - 1; i >= 0; --i) {
                swap(matrix[new_r][i], matrix[new_r][i - 1]);
            }
            matrix[new_r][0] = matrix[r][0];
        } else if (o == 4) {
            // Island reversal
            int r, c;
            cin >> r >> c;
            int new_r = r;
            int new_c = c;
            while (new_r < n && new_c < n) {
                if (matrix[new_r][new_c] == 1) {
                    swap(matrix[new_r][new_c], matrix[new_r + 1][new_c]);
                    swap(matrix[new_r][new_c], matrix[new_r][new_c + 1]);
                }
                new_r++;
                new_c++;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            cout << matrix[i][j] << " ";
        }
        cout << endl;
    }

    return 0;
}
