#include <iostream>
#include <string>
#include <algorithm>

std::string restoreString(int k, int n, std::vector<std::string>& s) {
    // Sort the strings based on their lengths
    std::sort(s.begin(), s.end(), [](const std::string& a, const std::string& b) {
        return a.length() < b.length();
    });

    // Iterate through the sorted strings
    for (int i = 0; i < k; ++i) {
        // Find the index of the first occurrence of the current string
        int j = 0;
        while (j < n && s[i][j] != s[i][j + 1]) {
            ++j;
        }

        // If no such index is found, return -1
        if (j == n) {
            return -1;
        }

        // Swap the characters at the found index with the next character
        std::swap(s[i][j], s[i][j + 1]);
    }

    // Return the modified string
    return s[0];
}

int main() {
    int k, n;
    std::cin >> k >> n;

    std::vector<std::string> s(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> s[i];
    }

    std::string result = restoreString(k, n, s);

    if (result == -1) {
        std::cout << "-1" << std::endl;
    } else {
        std::cout << result << std::endl;
    }

    return 0;
}
```

This solution reads from standard input, sorts the strings based on their lengths, and then iterates through them to find the optimal swap to restore the original strings. If no such swap exists, it returns -1. Otherwise, it returns the modified string.

