    int currentDepth = 0;
    for (int i = 0; i < W; ++i) {
        for (int j = 0; j < H; ++j) {
            if (formation[i][j] == 0) {
                continue;
            }
            int cost = formation[i][j];
            int oxygen = formation[i][j];
            int remainingOxygen = o - oxygen;
            int maxDepth = currentDepth + 1;
            int minDepth = currentDepth;
            while (maxDepth <= W && minDepth <= H) {
                int nextDepth = maxDepth;
                if (nextDepth > W || nextDepth > H) {
                    break;
                }
                if (formation[nextDepth][j] == 0) {
                    continue;
                }
                int nextCost = formation[nextDepth][j];
                int nextOxygen = formation[nextDepth][j];
                int remainingOxygen = o - nextOxygen;
                if (remainingOxygen >= 0) {
                    int newCost = cost + nextCost;
                    if (newCost < minCost) {
                        minCost = newCost;
                        currentDepth = nextDepth;
                    }
                } else {
                    break;
                }
                nextDepth++;
            }
        }
    }
    if (minCost == INT_MAX) {
        cout << "NA";
    } else {
