std::string determineStability(const std::string& input) {
    std::istringstream iss(input);
    std::string line;
    int w, h;
    iss >> w >> h;

    std::vector<std::vector<int>> pieces(w, std::vector<int>(h, 0));
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            iss >> pieces[i][j];
        }
    }

    int totalMass = 0;
    for (const auto& piece : pieces) {
        for (int mass : piece) {
            totalMass += mass;
        }
    }

    int unstableCount = 0;
    for (const auto& piece : pieces) {
        for (int mass : piece) {
            if (mass > totalMass / 2) {
                unstableCount++;
            }
        }
    }

    if (unstableCount == 0) {
        return "STABLE";
    } else {
        return "UNSTABLE";
    }
}

int main() {
