#include <unordered_set>

std::vector<int> solveDivisor(const std::vector<int>& cards, const std::vector<int>& ranks) {
    std::unordered_set<int> seen;
    std::vector<int> result;

    // Sort the ranks to make it easier to find the winning strategy
    std::sort(ranks.begin(), ranks.end());

    // Iterate through each card in the deck
    for (int i = 0; i < cards.size(); ++i) {
        int rank = cards[i];
        int sum = 0;

        // Calculate the sum of ranks in the current set
        for (int j = 0; j < ranks.size(); ++j) {
            if (ranks[j] == rank) {
                sum += j + 1;
                break;
            }
        }

        // Check if the current card can conquer the set
        if (sum % rank == 0) {
            seen.insert(rank);
            result.push_back(rank);
        }
    }

    // If no winning strategy was found, print "No"
    if (result.empty()) {
        std::cout << "No" << std::endl;
    } else {
        // Print the winning strategy as a list of N integers
        for (int i = 0; i < result.size(); ++i) {
            std::cout << result[i] << " ";
        }
        std::cout << std::endl;
    }

    return result;
}

int main() {
    int n;
