        for (int j = 0; j < W; ++j) {
            char c;
            cin >> c;
            grid[i][j] = c;
        }
    }

    // Directions for moving
    int dx[] = {0, 1, 0, -1};
    int dy[] = {1, 0, -1, 0};

    // Function to check if a cell is valid
    bool isValid(int x, int y) {
        return x >= 0 && x < W && y >= 0 && y < H;
    }

    // Function to check if the queen can escape
    bool canEscapeQueen(vector<vector<char>>& grid, int x, int y) {
        if (grid[x][y] == 'Q') {
            return false;
        }

        queue<pair<int, int>> q;
        q.push({x, y});

        while (!q.empty()) {
            int size = q.size();
            for (int i = 0; i < size; ++i) {
                auto [x, y] = q.front();
                q.pop();

                for (int d = 0; d < 4; ++d) {
                    int nx = x + dx[d];
                    int ny = y + dy[d];

                    if (isValid(nx, ny) && grid[nx][ny] == '.') {
                        grid[nx][ny] = 'Q';
                        q.push({nx, ny});
                    }
                }
            }
        }

        return true;
    }

    // Function to check if the army can catch the queen
    bool canCatchArmy(vector<vector<char>>& grid, int x, int y) {
        if (grid[x][y] == 'A') {
            return false;
        }

        queue<pair<int, int>> q;
        q.push({x, y});

        while (!q.empty()) {
            int size = q.size();
            for (int i = 0; i < size; ++i) {
                auto [x, y] = q.front();
                q.pop();

                for (int d = 0; d < 4; ++d) {
                    int nx = x + dx[d];
                    int ny = y + dy[d];

                    if (isValid(nx, ny) && grid[nx][ny] == '.') {
                        grid[nx][ny] = 'A';
                        q.push({nx, ny});
                    }
                }
            }
        }

        return true;
    }

    // Main loop
    for (int i = 0; i < H; ++i) {
        for (int j = 0; j < W; ++j) {
            if (grid[i][j] == 'Q') {
                if (canEscapeQueen(grid, i, j)) {
                    cout << "Queen can escape." << endl;
                } else {
                    cout << "Army can catch Queen." << endl;
                }
            } else if (grid[i][j] == 'A') {
                if (canCatchArmy(grid, i, j)) {
                    cout << "Queen can escape." << endl;
                } else {
                    cout << "Army can catch Queen." << endl;
                }
            }
        }
