            for(int j = 0; j < m; j++) {
                if(grid[i][j] == '.') {
                    int count = 0;
                    for(int k = max(0, i - x); k <= min(i + x, n - 1); k++) {
                        for(int l = max(0, j - y); l <= min(j + y, m - 1); l++) {
                            if(grid[k][l] == '*') {
                                count++;
                            }
                        }
                    }
                    ans = min(ans, count * (x + y));
                }
            }
        }
        cout << ans << endl;
    }
