    for (int i = 0; i < n; ++i) {
        // Calculate the time difference between the current train's departure time and the next train's departure time
        int timeDifference = departureTimes[i + 1] - departureTimes[i];

        // Check if the time difference is less than or equal to k
        if (timeDifference <= k) {
            // Increment the number of canceled trains
            canceledTrains++;
        } else {
            // Update the optimal starting time if the current train's departure time is later than the optimal starting time
            optimalStartingTime = std::max(optimalStartingTime, departureTimes[i]);
        }
