    std::cin >> n >> H;

    std::vector<std::pair<int, int>> polyline(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> polyline[i].first >> polyline[i].second;
    }

    double result = calculateDistance(polyline, n, H, H);
    std::cout << result << std::endl;

    return 0;
}
